import{_ as o,c as e,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Режим Ultrawork: активация всех функций одним кликом | oh-my-opencode","description":"Изучите режим Ultrawork и ключевые функции oh-my-opencode, включая использование ключевого слова ultrawork, изменения при активации, механизм параллельного исследования, обязательную проверку завершения и взаимодействие агентов для быстрой активации всех продвинутых функций.","frontmatter":{"title":"Режим Ultrawork: активация всех функций одним кликом | oh-my-opencode","sidebarTitle":"Активация всех функций одним кликом","subtitle":"Режим Ultrawork: активация всех функций одним кликом","description":"Изучите режим Ultrawork и ключевые функции oh-my-opencode, включая использование ключевого слова ultrawork, изменения при активации, механизм параллельного исследования, обязательную проверку завершения и взаимодействие агентов для быстрой активации всех продвинутых функций.","tags":["ultrawork","фоновые задачи","взаимодействие агентов"],"prerequisite":["/ru/code-yeongyu/oh-my-opencode/start/installation/","/ru/code-yeongyu/oh-my-opencode/start/sisyphus-orchestrator/"],"order":30},"headers":[],"relativePath":"ru/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"ru/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}'),l={name:"ru/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function d(i,t,s,n,c,u){return r(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="режим-ultrawork-активация-всех-функции-одним-кликом" tabindex="-1">Режим Ultrawork: активация всех функций одним кликом <a class="header-anchor" href="#режим-ultrawork-активация-всех-функции-одним-кликом" aria-label="Permalink to &quot;Режим Ultrawork: активация всех функций одним кликом&quot;">​</a></h1><h2 id="что-вы-сможете-сделать-после-изучения" tabindex="-1">Что вы сможете сделать после изучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-изучения" aria-label="Permalink to &quot;Что вы сможете сделать после изучения&quot;">​</a></h2><ul><li>Активировать все продвинутые функции oh-my-opencode одной фразой</li><li>Позволить нескольким AI-агентам работать параллельно как настоящая команда</li><li>Избежать ручной настройки нескольких агентов и фоновых задач</li><li>Понять философию дизайна и лучшие практики режима Ultrawork</li></ul><h2 id="ваши-текущие-проблемы" tabindex="-1">Ваши текущие проблемы <a class="header-anchor" href="#ваши-текущие-проблемы" aria-label="Permalink to &quot;Ваши текущие проблемы&quot;">​</a></h2><p>Возможно, вы сталкивались с такими ситуациями при разработке:</p><ul><li><strong>Слишком много функций, не знаете как использовать</strong>: 10 специализированных агентов, фоновые задачи, инструменты LSP, но не знаете как быстро активировать</li><li><strong>Требуется ручная настройка</strong>: Для каждой сложной задачи нужно вручную указывать агентов, фоновое параллелизм и другие настройки</li><li><strong>Неэффективное взаимодействие агентов</strong>: Последовательный вызов агентов, тратит время и ресурсы</li><li><strong>Задачи застревают на полпути</strong>: Агенты не имеют достаточной мотивации и ограничений для завершения задач</li></ul><p>Всё это мешает вам использовать истинную мощь oh-my-opencode.</p><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p><strong>Режим Ultrawork</strong> — это механизм &quot;активации всех функций одним кликом&quot; в oh-my-opencode.</p><div class="info custom-block"><p class="custom-block-title">Что такое режим Ultrawork?</p><p>Режим Ultrawork — это специальный режим работы, активируемый ключевым словом. Когда вы включаете <code>ultrawork</code> или сокращение <code>ulw</code> в свой запрос, система автоматически активирует все продвинутые функции: параллельные фоновые задачи, глубокое исследование, обязательное завершение, многоагентное взаимодействие и т.д.</p></div><h3 id="философия-дизаина" tabindex="-1">Философия дизайна <a class="header-anchor" href="#философия-дизаина" aria-label="Permalink to &quot;Философия дизайна&quot;">​</a></h3><p>Режим Ultrawork основан на следующих основных принципах (из <a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork Manifesto</a>):</p><table tabindex="0"><thead><tr><th>Принцип</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Человеческое вмешательство — это сигнал о неудаче</strong></td><td>Если вам нужно постоянно исправлять вывод AI, это означает проблему с дизайном системы</td></tr><tr><td><strong>Неразличимый код</strong></td><td>Код, написанный AI, не должен отличаться от кода опытного инженера</td></tr><tr><td><strong>Минимизация когнитивной нагрузки</strong></td><td>Вам нужно только сказать &quot;что делать&quot;, агенты отвечают за &quot;как делать&quot;</td></tr><tr><td><strong>Предсказуемый, устойчивый, делегируемый</strong></td><td>Агенты должны быть стабильны и надежны как компилятор</td></tr></tbody></table><h3 id="механизм-активации" tabindex="-1">Механизм активации <a class="header-anchor" href="#механизм-активации" aria-label="Permalink to &quot;Механизм активации&quot;">​</a></h3><p>Когда система обнаруживает ключевое слово <code>ultrawork</code> или <code>ulw</code>:</p><ol><li><strong>Установка режима максимальной точности</strong>: <code>message.variant = &quot;max&quot;</code></li><li><strong>Отображение Toast-уведомления</strong>: &quot;Ultrawork Mode Activated - Maximum precision engaged. All agents at your disposal.&quot;</li><li><strong>Внедрение полных инструкций</strong>: Внедрение в агента более 200 строк инструкций ULTRAWORK, включая: <ul><li>Обязательное определение на 100% перед началом реализации</li><li>Требование параллельного использования фоновых задач</li><li>Обязательное использование системы Category + Skills</li><li>Обязательная проверка завершения (рабочий процесс TDD)</li><li>Запрет любых оправданий &quot;я не могу&quot;</li></ul></li></ol><h2 id="следуите-инструкциям" tabindex="-1">Следуйте инструкциям <a class="header-anchor" href="#следуите-инструкциям" aria-label="Permalink to &quot;Следуйте инструкциям&quot;">​</a></h2><h3 id="шаг-1-активация-режима-ultrawork" tabindex="-1">Шаг 1: Активация режима Ultrawork <a class="header-anchor" href="#шаг-1-активация-режима-ultrawork" aria-label="Permalink to &quot;Шаг 1: Активация режима Ultrawork&quot;">​</a></h3><p>Введите запрос, содержащий ключевое слово <code>ultrawork</code> или <code>ulw</code> в OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork разработать REST API</span></span></code></pre></div><p>Или более кратко:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw добавить аутентификацию пользователей</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>:</p><ul><li>В интерфейсе появляется Toast-уведомление: &quot;Ultrawork Mode Activated&quot;</li><li>Ответ агента начинается с &quot;ULTRAWORK MODE ENABLED!&quot;</li></ul><h3 id="шаг-2-наблюдение-за-изменениями-поведения-агента" tabindex="-1">Шаг 2: Наблюдение за изменениями поведения агента <a class="header-anchor" href="#шаг-2-наблюдение-за-изменениями-поведения-агента" aria-label="Permalink to &quot;Шаг 2: Наблюдение за изменениями поведения агента&quot;">​</a></h3><p>После активации режима Ultrawork агент будет:</p><ol><li><p><strong>Параллельно исследовать кодовую базу</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;найти существующие паттерны API&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;найти инфраструктуру тестирования&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;найти лучшие практики аутентификации&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>Вызывать агента Plan для создания рабочего плана</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;создать подробный план на основе собранного контекста&quot;)</span></span></code></pre></div></li><li><p><strong>Использовать Category + Skills для выполнения задач</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>Что вы должны увидеть</strong>:</p><ul><li>Несколько фоновых задач выполняются одновременно</li><li>Агент активно вызывает специализированных агентов (Oracle, Librarian, Explore)</li><li>Полный план тестирования и разложение работы</li><li>Задача выполняется непрерывно до 100% завершения</li></ul><h3 id="шаг-3-проверка-завершения-задачи" tabindex="-1">Шаг 3: Проверка завершения задачи <a class="header-anchor" href="#шаг-3-проверка-завершения-задачи" aria-label="Permalink to &quot;Шаг 3: Проверка завершения задачи&quot;">​</a></h3><p>После завершения агент:</p><ol><li><strong>Покажет доказательства проверки</strong>: вывод фактически запущенных тестов, описание ручной проверки</li><li><strong>Подтвердит завершение всех TODO</strong>: не объявит завершение заранее</li><li><strong>Подведёт итоги работы</strong>: перечислит что было сделано и почему</li></ol><p><strong>Что вы должны увидеть</strong>:</p><ul><li>Чёткие результаты тестирования (не &quot;должно работать&quot;)</li><li>Все проблемы решены</li><li>Нет незавершённых списков TODO</li></ul><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><p>После выполнения вышеуказанных шагов подтвердите:</p><ul><li>[ ] После ввода <code>ulw</code> вы видите Toast-уведомление</li><li>[ ] Ответ агента начинается с &quot;ULTRAWORK MODE ENABLED!&quot;</li><li>[ ] Наблюдается выполнение параллельных фоновых задач</li><li>[ ] Агент использует систему Category + Skills</li><li>[ ] После завершения задачи есть доказательства проверки</li></ul><p>Если какой-либо пункт не пройден, проверьте:</p><ul><li>Правильность написания ключевого слова (<code>ultrawork</code> или <code>ulw</code>)</li><li>Находитесь ли вы в основном сеансе (фоновые задачи не активируют режим)</li><li>Включены ли соответствующие функции в файле конфигурации</li></ul><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Сценарий</th><th>Использовать Ultrawork</th><th>Обычный режим</th></tr></thead><tbody><tr><td><strong>Сложная новая функция</strong></td><td>✅ Рекомендуется (требуется многоагентное взаимодействие)</td><td>❌ Может быть недостаточно эффективно</td></tr><tr><td><strong>Срочное исправление</strong></td><td>✅ Рекомендуется (требуется быстрая диагностика и исследование)</td><td>❌ Может пропустить контекст</td></tr><tr><td><strong>Простое изменение</strong></td><td>❌ Избыточно (тратит ресурсы)</td><td>✅ Более подходит</td></tr><tr><td><strong>Быстрая проверка идеи</strong></td><td>❌ Избыточно</td><td>✅ Более подходит</td></tr></tbody></table><p><strong>Эмпирическое правило</strong>:</p><ul><li>Задача затрагивает несколько модулей или систем → используйте <code>ulw</code></li><li>Требуется глубокое исследование кодовой базы → используйте <code>ulw</code></li><li>Требуется вызов нескольких специализированных агентов → используйте <code>ulw</code></li><li>Небольшое изменение в одном файле → не нужно <code>ulw</code></li></ul><h2 id="предупреждения" tabindex="-1">Предупреждения <a class="header-anchor" href="#предупреждения" aria-label="Permalink to &quot;Предупреждения&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Меры предосторожности</p><p><strong>1. Не используйте <code>ulw</code> в каждом запросе</strong></p><p>Режим Ultrawork внедряет большое количество инструкций, для простых задач это избыточно. Используйте только для действительно сложных задач, требующих многоагентного взаимодействия, параллельного исследования, глубокого анализа.</p><p><strong>2. Фоновые задачи не активируют режим Ultrawork</strong></p><p>Детектор ключевых слов пропускает фоновые сеансы, чтобы избежать ошибочного внедрения режима в подагентов. Режим Ultrawork работает только в основном сеансе.</p><p><strong>3. Убедитесь в правильности конфигурации Provider</strong></p><p>Режим Ultrawork зависит от параллельной работы нескольких AI-моделей. Если некоторые Provider не настроены или недоступны, агент может не вызвать специализированных агентов.</p></div><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><p>Режим Ultrawork активируется ключевым словом и реализует цель дизайна &quot;активация всех функций одной фразой&quot;:</p><ul><li><strong>Простота использования</strong>: просто введите <code>ulw</code> для активации</li><li><strong>Автоматическое взаимодействие</strong>: агенты автоматически вызывают других агентов, параллельно выполняют фоновые задачи</li><li><strong>Обязательное завершение</strong>: полный механизм проверки обеспечивает 100% завершение</li><li><strong>Нулевая настройка</strong>: не нужно вручную устанавливать_PRIORITеты агентов, ограничения параллелизма и т.д.</li></ul><p>Помните: режим Ultrawork предназначен для того, чтобы агенты работали как настоящая команда, вам нужно только выразить намерение, агенты отвечают за выполнение.</p><h2 id="предварительныи-обзор-следующего-урока" tabindex="-1">Предварительный обзор следующего урока <a class="header-anchor" href="#предварительныи-обзор-следующего-урока" aria-label="Permalink to &quot;Предварительный обзор следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../../platforms/provider-setup/">Настройка Provider</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как настроить несколько Provider: Anthropic, OpenAI, Google и т.д.</li><li>Как стратегия нескольких моделей автоматически понижает и выбирает оптимальную модель</li><li>Как проверить соединение Provider и использование квот</li></ul></blockquote><hr><h2 id="приложение-ссылки-на-исходныи-код" tabindex="-1">Приложение: Ссылки на исходный код <a class="header-anchor" href="#приложение-ссылки-на-исходныи-код" aria-label="Permalink to &quot;Приложение: Ссылки на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Философия дизайна Ultrawork</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>Hook детектора ключевых слов</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/index.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/index.ts</code></a></td><td>12-100</td></tr><tr><td>Шаблон инструкций ULTRAWORK</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>Логика детектора ключевых слов</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/detector.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/detector.ts</code></a></td><td>26-53</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>KEYWORD_DETECTORS</code>: конфигурация детекторов ключевых слов, включает три режима: ultrawork, search, analyze</li><li><code>CODE_BLOCK_PATTERN</code>: регулярное выражение для кодовых блоков, используется для фильтрации ключевых слов в кодовых блоках</li><li><code>INLINE_CODE_PATTERN</code>: регулярное выражение для встроенного кода, используется для фильтрации ключевых слов во встроенном коде</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>createKeywordDetectorHook()</code>: создаёт Hook детектора ключевых слов, отслеживает событие UserPromptSubmit</li><li><code>detectKeywordsWithType()</code>: обнаруживает ключевые слова в тексте и возвращает тип (ultrawork/search/analyze)</li><li><code>getUltraworkMessage()</code>: генерирует полные инструкции режима ULTRAWORK (выбирает режим Planner или обычный в зависимости от типа агента)</li><li><code>removeCodeBlocks()</code>: удаляет кодовые блоки из текста, чтобы избежать ложного срабатывания ключевых слов в кодовых блоках</li></ul><p><strong>Бизнес-правила</strong>:</p><table tabindex="0"><thead><tr><th>ID правила</th><th>Описание правила</th><th>Метка</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>При обнаружении &quot;ultrawork&quot; или &quot;ulw&quot; активируется режим Ultrawork</td><td>【Факт】</td></tr><tr><td>BR-4.8.4-2</td><td>Режим Ultrawork устанавливает <code>message.variant = &quot;max&quot;</code></td><td>【Факт】</td></tr><tr><td>BR-4.8.4-3</td><td>Режим Ultrawork отображает Toast-уведомление: &quot;Ultrawork Mode Activated&quot;</td><td>【Факт】</td></tr><tr><td>BR-4.8.4-4</td><td>Фоновые задачи пропускают детекцию ключевых слов, чтобы избежать внедрения режима</td><td>【Факт】</td></tr><tr><td>BR-4.8.4-5</td><td>В неосновных сеансах разрешено только ключевое слово ultrawork, блокируется внедрение других режимов</td><td>【Факт】</td></tr></tbody></table></details>`,54)])])}const g=o(l,[["render",d]]);export{h as __pageData,g as default};
